queries.sparql:
PREFIX : <http://ambrosia.example.org/traffic#>
PREFIX p: <http://ambrosia.example.org/traffic/prop#>
SELECT ?aid WHERE {
  { SELECT ?term (COUNT(DISTINCT ?ap) AS ?nf) WHERE { ?l p:hasTerminals ?term ; p:hasAirports ?ap . } GROUP BY ?term }
  ?term p:hasAirports ?ta . ?ta p:id ?aid .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Airports } }
  FILTER(?nf = ?total)
}

PREFIX : <http://ambrosia.example.org/traffic#>
PREFIX p: <http://ambrosia.example.org/traffic/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasTerminals ?child ; p:hasAirports ?parent . } GROUP BY ?child }
  ?child p:type ?type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Airports } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/traffic#>
PREFIX p: <http://ambrosia.example.org/traffic/prop#>
CHOICE scope {
  collective: { SELECT ?aid WHERE {
  { SELECT ?term (COUNT(DISTINCT ?ap) AS ?nf) WHERE { ?l p:hasTerminals ?term ; p:hasAirports ?ap . } GROUP BY ?term }
  ?term p:hasAirports ?ta . ?ta p:id ?aid .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Airports } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?airport_id WHERE {
  ?airports_terminals a :Airports_Terminals .
  ?terminals a :Terminals .
  ?airports_terminals p:hasTerminals ?terminals .
  ?airports a :Airports .
  ?terminals p:hasAirports ?airports .
  ?airports p:name ?name .
  ?terminals p:hasAirports ?airport_id_ref .
  ?airport_id_ref p:id ?airport_id .
} }
}

